#include<bits/stdc++.h>
using namespace std;
const int mod = 1e5 + 3;
int main() {
	long long ans = 1, ans2 = 1;
	int a, b, c, d, k;
	cin >> a >> b >> c >> d >> k;
	int n = a + c;
	int m = b + d;
	int e = n;
	int f = m;
	for (int i = 1; i <= k; i++) {
		ans *= (e * f);
		ans %= mod;
		e--;
		f--;
	}
	e = n - 1;
	f = m - 1;
	ans2 = c * b;
	for (int i = 2; i <= k; i++) {
		ans2 *= (e * f);
		ans2 %= mod;
		e--;
		f--;
	}
	cout << ans - ans2;
	return 0;
}
